INSERT INTO `activity_logs` (`id`, `module`, `sub_module`, `item_id`, `item_name`, `action`, `data_before`, `data_after`, `user_id`, `user_name`, `ip_address`, `user_agent`, `created_at`) VALUES (108, 'SYSTEM', 'ROLES', '4', 'Area Manager', 'UPDATE', '{\"id\":\"4\",\"role_name\":\"Area Manager\",\"description\":\"Eksekutif Area\",\"is_superadmin\":\"0\",\"can_add_user\":\"0\",\"can_view_all_users\":\"0\",\"created_at\":\"2026-03-05 12:43:36\",\"updated_at\":null,\"deleted_at\":null}', '{\"role_name\":\"Area Manager\",\"description\":\"Deskripsi Role: Untuk para Leader pemegang keputusan. Hanya butuh kecepatan informasi (Dasbor) dan rekap laporan kerja tanpa harus pusing melihat tombol \\\"Ubah \\/ Hapus\\\" data teknis.\\r\\n\\r\\nHak Menu yang dicentang: Dashboard Eksekutif Area, Laporan (Report\\/Export Excel), Peta Sebaran ODC\\/ODP, Validasi Akhir (Tutup Buku\\/Proyek).\\r\\nJabatan yang akan dihubungkan ke Role ini:\\r\\nHead Of Service Area\\r\\n(Jika ada kelak) Branch Manager \\/ GM\",\"can_add_user\":0,\"can_view_all_users\":0,\"updated_at\":\"2026-03-05 12:44:44\"}', 1, 'Super Administrator', '127.0.0.1', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64; rv:148.0) Gecko/20100101 Firefox/148.0', '2026-03-05 12:44:44');
INSERT INTO `activity_logs` (`id`, `module`, `sub_module`, `item_id`, `item_name`, `action`, `data_before`, `data_after`, `user_id`, `user_name`, `ip_address`, `user_agent`, `created_at`) VALUES (109, 'SYSTEM', 'ROLES', '5', 'Area Coordinator', 'UPDATE', '{\"id\":\"5\",\"role_name\":\"Area Coordinator\",\"description\":\"Koordinator Operasional\",\"is_superadmin\":\"0\",\"can_add_user\":\"0\",\"can_view_all_users\":\"0\",\"created_at\":\"2026-03-05 12:43:36\",\"updated_at\":null,\"deleted_at\":null}', '{\"role_name\":\"Area Coordinator\",\"description\":\"Deskripsi Role: Untuk staf level atas (Officer) yang mengatur alur ritme di atas kertas. Mereka yang berwenang menekan tombol \\\"Approve\\\" (Menyetujui BoQ) atau \\\"Reject\\\" (Menolak bukti lapangan dari teknisi jika buram\\/fiktif).\\r\\n\\r\\nHak Menu yang dicentang: Dashboard Area, Validasi Evidence Teknisi, Persetujuan Pendanaan (BoQ Approval), Pantauan Kinerja Harian.\\r\\nJabatan yang akan dihubungkan ke Role ini:\\r\\nOfficer 3 Service Area\\r\\nOfficer 1 Assurance & Maintenance\",\"can_add_user\":0,\"can_view_all_users\":0,\"updated_at\":\"2026-03-05 12:46:48\"}', 1, 'Super Administrator', '127.0.0.1', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64; rv:148.0) Gecko/20100101 Firefox/148.0', '2026-03-05 12:46:48');
INSERT INTO `activity_logs` (`id`, `module`, `sub_module`, `item_id`, `item_name`, `action`, `data_before`, `data_after`, `user_id`, `user_name`, `ip_address`, `user_agent`, `created_at`) VALUES (110, 'SYSTEM', 'ROLES', '6', 'Helpdesk', 'UPDATE', '{\"id\":\"6\",\"role_name\":\"Helpdesk\",\"description\":\"Operator Pusat Bantuan\",\"is_superadmin\":\"0\",\"can_add_user\":\"0\",\"can_view_all_users\":\"0\",\"created_at\":\"2026-03-05 12:43:36\",\"updated_at\":null,\"deleted_at\":null}', '{\"role_name\":\"Helpdesk\",\"description\":\"Deskripsi Role: Ini adalah \\\"pintu gerbang\\\" pertama aplikasi. Merekalah yang menerima panggilan telepon\\/laporan WA pelanggan dan mengubahnya menjadi Tiket, lalu \\\"melempar\\\" (Dispatch) tiket tersebut ke aplikasi HP para teknisi.\\r\\n\\r\\nHak Menu yang dicentang: Input Tiket Baru, Daftar Tiket Terbuka (Open Tickets), Peta Teknisi (Tracking), Alokasi Tugas (Assignment Menu).\\r\\nJabatan yang akan dihubungkan ke Role ini:\\r\\nHelpdesk\",\"can_add_user\":0,\"can_view_all_users\":0,\"updated_at\":\"2026-03-05 12:51:56\"}', 1, 'Super Administrator', '127.0.0.1', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64; rv:148.0) Gecko/20100101 Firefox/148.0', '2026-03-05 12:51:56');
INSERT INTO `activity_logs` (`id`, `module`, `sub_module`, `item_id`, `item_name`, `action`, `data_before`, `data_after`, `user_id`, `user_name`, `ip_address`, `user_agent`, `created_at`) VALUES (111, 'SYSTEM', 'ROLES', '7', 'Back-Office Support', 'UPDATE', '{\"id\":\"7\",\"role_name\":\"Back-Office Support\",\"description\":\"Staf Dukungan Internal\",\"is_superadmin\":\"0\",\"can_add_user\":\"0\",\"can_view_all_users\":\"0\",\"created_at\":\"2026-03-05 12:43:36\",\"updated_at\":null,\"deleted_at\":null}', '{\"role_name\":\"Back-Office Support\",\"description\":\"Deskripsi Role: Mereka yang bekerja di depan layar komputer kantor untuk membantu proses eksekusi, misalnya remote restart peranti (OLT), pembaruan data rak, koordinasi material gudang untuk tim pemeliharaan (Maintenance).\\r\\n\\r\\nHak Menu yang dicentang: Data Center \\/ Inventaris OLT, Pencatatan Material Keluar, Update Data Redaman (Sistem), Validasi Administratif.\\r\\nJabatan yang akan dihubungkan ke Role ini:\\r\\nStaf Assurance\\r\\nStaff Maintenance\",\"can_add_user\":0,\"can_view_all_users\":0,\"updated_at\":\"2026-03-05 12:52:15\"}', 1, 'Super Administrator', '127.0.0.1', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64; rv:148.0) Gecko/20100101 Firefox/148.0', '2026-03-05 12:52:15');
INSERT INTO `activity_logs` (`id`, `module`, `sub_module`, `item_id`, `item_name`, `action`, `data_before`, `data_after`, `user_id`, `user_name`, `ip_address`, `user_agent`, `created_at`) VALUES (112, 'SYSTEM', 'ROLES', '8', 'Field Technician', 'UPDATE', '{\"id\":\"8\",\"role_name\":\"Field Technician\",\"description\":\"Teknisi Lapangan\",\"is_superadmin\":\"0\",\"can_add_user\":\"0\",\"can_view_all_users\":\"0\",\"created_at\":\"2026-03-05 12:43:36\",\"updated_at\":null,\"deleted_at\":null}', '{\"role_name\":\"Field Technician\",\"description\":\"Deskripsi Role: Kasta paling ujung tombak. Aplikasi mereka harus sangat sederhana karena dibuka menggunakan HP di atas tiang\\/tangga. Tidak ada menu tambah\\/hapus berlebihan.\\r\\n\\r\\nHak Menu yang dicentang: Antrean Tiket \\\"Tugas Saya\\\" (My Tasks), Tombol \\\"Update Progress\\\" (Tiba di Lokasi \\/ Selesai Pekerjaan), Kamera\\/Upload Bukti (Evidence Foto), dan Tulis Rincian Material (BoQ).\\r\\nJabatan yang akan dihubungkan ke Role ini:\\r\\nTenaga Teknis (Teknisi Lapangan)\",\"can_add_user\":0,\"can_view_all_users\":0,\"updated_at\":\"2026-03-05 12:52:30\"}', 1, 'Super Administrator', '127.0.0.1', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64; rv:148.0) Gecko/20100101 Firefox/148.0', '2026-03-05 12:52:30');
