INSERT INTO `roles` (`id`, `role_name`, `description`, `is_superadmin`, `can_add_user`, `can_view_all_users`, `created_at`, `updated_at`, `deleted_at`) VALUES (4, 'Area Manager', 'Deskripsi Role: Untuk para Leader pemegang keputusan. Hanya butuh kecepatan informasi (Dasbor) dan rekap laporan kerja tanpa harus pusing melihat tombol \"Ubah / Hapus\" data teknis.\n\nHak Menu yang dicentang: Dashboard Eksekutif Area, Laporan (Report/Export Excel), Peta Sebaran ODC/ODP, Validasi Akhir (Tutup Buku/Proyek).\nJabatan yang akan dihubungkan ke Role ini:\nHead Of Service Area\n(Jika ada kelak) Branch Manager / GM', 0, 0, 0, '2026-03-05 12:43:36', '2026-03-05 12:44:44', NULL);
INSERT INTO `roles` (`id`, `role_name`, `description`, `is_superadmin`, `can_add_user`, `can_view_all_users`, `created_at`, `updated_at`, `deleted_at`) VALUES (5, 'Area Coordinator', 'Deskripsi Role: Untuk staf level atas (Officer) yang mengatur alur ritme di atas kertas. Mereka yang berwenang menekan tombol \"Approve\" (Menyetujui BoQ) atau \"Reject\" (Menolak bukti lapangan dari teknisi jika buram/fiktif).\r\n\r\nHak Menu yang dicentang: Dashboard Area, Validasi Evidence Teknisi, Persetujuan Pendanaan (BoQ Approval), Pantauan Kinerja Harian.\r\nJabatan yang akan dihubungkan ke Role ini:\r\nOfficer 3 Service Area\r\nOfficer 1 Assurance & Maintenance', 0, 0, 0, '2026-03-05 12:43:36', '2026-03-05 12:46:48', NULL);
INSERT INTO `roles` (`id`, `role_name`, `description`, `is_superadmin`, `can_add_user`, `can_view_all_users`, `created_at`, `updated_at`, `deleted_at`) VALUES (6, 'Helpdesk', 'Deskripsi Role: Ini adalah \"pintu gerbang\" pertama aplikasi. Merekalah yang menerima panggilan telepon/laporan WA pelanggan dan mengubahnya menjadi Tiket, lalu \"melempar\" (Dispatch) tiket tersebut ke aplikasi HP para teknisi.\r\n\r\nHak Menu yang dicentang: Input Tiket Baru, Daftar Tiket Terbuka (Open Tickets), Peta Teknisi (Tracking), Alokasi Tugas (Assignment Menu).\r\nJabatan yang akan dihubungkan ke Role ini:\r\nHelpdesk', 0, 0, 0, '2026-03-05 12:43:36', '2026-03-05 12:51:56', NULL);
INSERT INTO `roles` (`id`, `role_name`, `description`, `is_superadmin`, `can_add_user`, `can_view_all_users`, `created_at`, `updated_at`, `deleted_at`) VALUES (7, 'Back-Office Support', 'Deskripsi Role: Mereka yang bekerja di depan layar komputer kantor untuk membantu proses eksekusi, misalnya remote restart peranti (OLT), pembaruan data rak, koordinasi material gudang untuk tim pemeliharaan (Maintenance).\r\n\r\nHak Menu yang dicentang: Data Center / Inventaris OLT, Pencatatan Material Keluar, Update Data Redaman (Sistem), Validasi Administratif.\r\nJabatan yang akan dihubungkan ke Role ini:\r\nStaf Assurance\r\nStaff Maintenance', 0, 0, 0, '2026-03-05 12:43:36', '2026-03-05 12:52:15', NULL);
INSERT INTO `roles` (`id`, `role_name`, `description`, `is_superadmin`, `can_add_user`, `can_view_all_users`, `created_at`, `updated_at`, `deleted_at`) VALUES (8, 'Field Technician', 'Deskripsi Role: Kasta paling ujung tombak. Aplikasi mereka harus sangat sederhana karena dibuka menggunakan HP di atas tiang/tangga. Tidak ada menu tambah/hapus berlebihan.\r\n\r\nHak Menu yang dicentang: Antrean Tiket \"Tugas Saya\" (My Tasks), Tombol \"Update Progress\" (Tiba di Lokasi / Selesai Pekerjaan), Kamera/Upload Bukti (Evidence Foto), dan Tulis Rincian Material (BoQ).\r\nJabatan yang akan dihubungkan ke Role ini:\r\nTenaga Teknis (Teknisi Lapangan)', 0, 0, 0, '2026-03-05 12:43:36', '2026-03-05 12:52:30', NULL);
